 10→{
 11→ 	// Set this actor to call Tick() every frame.  You can turn this off to improve performance if you don't need it.
 12→	PrimaryActorTick.bCanEverTick = true;
 13→
 14→	// �������������
 15→	RootSceneComponent = CreateDefaultSubobject<USceneComponent>(TEXT("RootComponent"));
 16→	RootComponent = RootSceneComponent;
 17→
 18→	// 创建视觉精灵组件
 19→	SpriteComponent = CreateDefaultSubobject<UPaperSpriteComponent>(TEXT("SpriteComponent"));
 20→	SpriteComponent->SetupAttachment(RootComponent);
 21→
 22→	// 创建装饰精灵组件（在基础精灵上方）
 23→	DecorationSpriteComponent = CreateDefaultSubobject<UPaperSpriteComponent>(TEXT("DecorationSpriteComponent"));
 24→	DecorationSpriteComponent->SetupAttachment(RootComponent);
 25→	DecorationSpriteComponent->SetRelativeLocation(FVector(0, 0, 0.5f));
 26→
 27→	// 创建范围覆盖层精灵（半透明填充，Z=0.3f）
 28→	OverlaySpriteComponent = CreateDefaultSubobject<UPaperSpriteComponent>(TEXT("OverlaySpriteComponent"));
 29→	OverlaySpriteComponent->SetupAttachment(RootComponent);
 30→	OverlaySpriteComponent->SetRelativeLocation(FVector(0, 0, 0.3f));
 31→	OverlaySpriteComponent->SetVisibility(false);
 32→
 33→	// 创建 6 个边缘精灵组件
 34→	EdgeSpriteComponents.SetNum(6);
 35→	for (int32 i = 0; i < 6; i++)
 36→	{
 37→		FName CompName = *FString::Printf(TEXT("EdgeSprite_%d"), i);
 38→		EdgeSpriteComponents[i] = CreateDefaultSubobject<UPaperSpriteComponent>(CompName);
 39→		EdgeSpriteComponents[i]->SetupAttachment(RootComponent);
 40→		EdgeSpriteComponents[i]->SetVisibility(false);
 41→	}
 42→}
