114→void ALFPHexTile::ShowEdge(int32 DirIndex, FLinearColor Color)
115→{
116→	if (EdgeSpriteComponents.IsValidIndex(DirIndex) && EdgeSpriteComponents[DirIndex])
117→	{
118→		EdgeSpriteComponents[DirIndex]->SetSpriteColor(Color);
119→		EdgeSpriteComponents[DirIndex]->SetVisibility(true);
120→	}
121→}
