140→void ALFPHexTile::ShowPathOverlay(bool bActive, FLinearColor Color)
141→{
142→	if (OverlaySpriteComponent)
143→	{
144→		if (bActive)
145→		{
146→			OverlaySpriteComponent->SetSpriteColor(Color);
147→			OverlaySpriteComponent->SetVisibility(true);
148→		}
149→		else
150→		{
151→			OverlaySpriteComponent->SetVisibility(false);
152→		}
153→	}
154→}
