230→bool ALFPHexGridManager::SaveMapToCSV(const FString& CSVFilePath)
231→{
232→	// CSV 头部（UE DataTable 格式：第一列为 RowName）
233→	FString CSVContent = TEXT("---,Q,R,TerrainType,DecorationID,SpawnFaction,SpawnIndex,EventTag\n");
234→
235→	for (const auto& Pair : GridMap)
236→	{
237→		ALFPHexTile* Tile = Pair.Value;
238→		if (!Tile) continue;
239→
240→		FLFPHexCoordinates Coord = Tile->GetCoordinates();
241→		FString RowName = FString::Printf(TEXT("%d_%d"), Coord.Q, Coord.R);
242→
243→		// 地形类型枚举名
244→		ELFPTerrainType TType = Tile->GetTerrainData() ? Tile->GetTerrainData()->TerrainType : ELFPTerrainType::TT_Grass;
245→		FString TerrainStr = UEnum::GetValueAsString(TType);
246→		TerrainStr = TerrainStr.RightChop(TerrainStr.Find(TEXT("::")) + 2);
247→
248→		// 装饰 ID
249→		FString DecoStr = Tile->DecorationID.IsNone() ? TEXT("") : Tile->DecorationID.ToString();
250→
251→		// 出生点阵营
252→		FString SpawnStr = UEnum::GetValueAsString(Tile->SpawnFaction);
253→		SpawnStr = SpawnStr.RightChop(SpawnStr.Find(TEXT("::")) + 2);
254→
255→		// 事件标签
256→		FString EventStr = Tile->EventTag.IsValid() ? Tile->EventTag.ToString() : TEXT("");
257→
258→		CSVContent += FString::Printf(TEXT("%s,%d,%d,%s,%s,%s,%d,%s\n"),
259→			*RowName, Coord.Q, Coord.R, *TerrainStr, *DecoStr,
260→			*SpawnStr, Tile->SpawnIndex, *EventStr);
261→	}
262→
263→	// 确保目录存在
264→	FString Directory = FPaths::GetPath(CSVFilePath);
265→	if (!FPaths::DirectoryExists(Directory))
266→	{
267→		IFileManager::Get().MakeDirectory(*Directory, true);
268→	}
269→
270→	bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *CSVFilePath,
271→		FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
272→
273→	if (bSuccess)
274→	{
275→		UE_LOG(LogTemp, Log, TEXT("SaveMapToCSV: 保存 %d 个格子到 %s"), GridMap.Num(), *CSVFilePath);
276→	}
277→	else
278→	{
279→		UE_LOG(LogTemp, Error, TEXT("SaveMapToCSV: 保存失败 %s"), *CSVFilePath);
280→	}
281→	return bSuccess;
282→}
