void ALFPHexGridManager::UpdateTileTransitions(ALFPHexTile* Tile)
{
    if (!Tile || !bEnableTerrainTransitions) return;

    ULFPTerrainDataAsset* TileTerrainData = Tile->GetTerrainData();
    if (!TileTerrainData) return;

    int32 TilePriority = TileTerrainData->RenderPriority;

    // 更新基础地形材质
    if (TileTerrainData->TerrainTexture)
    {
        Tile->UpdateBaseTerrainMaterial(TileTerrainData->TerrainTexture, TerrainTextureScale);
    }

    FLFPHexCoordinates TileCoord = Tile->GetCoordinates();

    for (int32 DirIdx = 0; DirIdx < 6; DirIdx++)
    {
        // 查找此方向的邻居
        FLFPHexCoordinates NeighborCoord(
            TileCoord.Q + HexDirections[DirIdx].Q,
            TileCoord.R + HexDirections[DirIdx].R
        );
        ALFPHexTile* Neighbor = GetTileAtCoordinates(NeighborCoord);

        if (!Neighbor)
        {
            // 无邻居（地图边缘），不显示过渡
            Tile->ClearTransitionForDirection(DirIdx);
            continue;
        }

        ULFPTerrainDataAsset* NeighborTerrainData = Neighbor->GetTerrainData();
        if (!NeighborTerrainData)
        {
            Tile->ClearTransitionForDirection(DirIdx);
            continue;
        }

        int32 NeighborPriority = NeighborTerrainData->RenderPriority;

        if (NeighborPriority > TilePriority && NeighborTerrainData->TerrainTexture)
        {
            // 邻居优先级更高 → 邻居纹理向本格渗透
            float MaskRotation = TransitionMaskRotations[DirIdx];
            Tile->UpdateTransitionForDirection(DirIdx,
                NeighborTerrainData->TerrainTexture,
                MaskRotation,
                TerrainTextureScale);
        }
        else
        {
            // 同级或本格更高 → 不显示过渡
            Tile->ClearTransitionForDirection(DirIdx);
        }
    }
}
```

